import numpy as np

def layer_norm(
    x: np.ndarray,
    gamma: np.ndarray,
    beta: np.ndarray,
    eps: float = 1e-5
) -> np.ndarray:
    mean = x.mean(axis=-1, keepdims=True)        # (n, 1)
    var = x.var(axis=-1, keepdims=True)          # (n, 1)
    x_hat = (x - mean) / np.sqrt(var + eps)     # (n, d)
    return gamma * x_hat + beta                  # (n, d)
